var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"저리 비켜, 이 망할 침식체가!!","JPN":"退け、くそったれの侵食体め！！","ENG":"Get out of the way, darn Corrupted Objects!!","TWN":"走開！該死的侵蝕體！！"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"후우…… 흐으…… 으읏……!","JPN":"ふう……くぅ……うぅ……！","ENG":"Phew... Urgh... Ngh...!","TWN":"呼呼……呼……呃……！"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L11_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"손님……. 왜 그래……?","JPN":"お客さん……どうしたの……？","ENG":"My dear guest... What’s the matter...?","TWN":"客人……你還好嗎……？"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L12_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"알면서 물어보는 거죠?! 이대로면 다 죽게 생겼으니까 그러죠!","JPN":"わざとですよね！？　このままじゃみんな死ぬことになるからですよ！","ENG":"You already know, right? We’re all going to die if this keeps up!","TWN":"你是明知故問嗎？！我不這樣的話，就是大家一起死！"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L14_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"그렇다면 도망쳐. 중사님.","JPN":"だったら逃げなさい、軍曹。","ENG":"Then feel free to run away, Sergeant.","TWN":"中士，你們快逃吧！"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"손짓 한 번으로 도시 구획 하나를 지워 버리는 상대야. 도망친다고 나무랄 사람 아무도 없어.","JPN":"手を一振りしただけで都市の区画一つを消してしまう相手よ。逃げたって誰も責めないの。","ENG":"Our enemy can wipe out an entire city block with a flick of the wrist. No one could blame you for running away.","TWN":"對方可是彈指之間就能毀掉整座城市，就算你逃走也沒人會怪你的！"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"도망은……!","JPN":"逃げるなんて……！","ENG":"Running away...!","TWN":"逃走……！"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"귀관의 공헌에 감사합니다.","JPN":"貴官の貢献に感謝します。","ENG":"Thank you for all you’ve done.","TWN":"謝謝中士的貢獻。"},"stage":{"bg":"HARMONY_03","bgm":"THEMA_DIVE_EATER","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"귀관이 아니었으면…… 이 풍경은 볼 수 없었을 겁니다.","JPN":"貴官がいなかったら……この景色を見ることは叶いませんでした。","ENG":"If it weren’t for you... We never would have been able to witness this moment.","TWN":"因為中士……才能看到這樣的場景。"},"stage":{"bg":"HARMONY_03","bgm":"THEMA_DIVE_EATER","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"그런 말을 듣고 어떻게 도망쳐요……!","JPN":"そんなことを聞いて逃げられるわけがないでしょ……！","ENG":"How can I run after hearing something like that...!","TWN":"說這種話叫我怎麼逃……！"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_ON","text":{"KOREA":"호오…….","JPN":"ほう……","ENG":"Ooh...","TWN":"呵……"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_ON","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_ON","text":{"KOREA":"그러고 보니 귀가 좋은 아이가 있었죠.","JPN":"そういえば、音感がいい子がいましたね。","ENG":"Now that I think of it, there was a kid with a good ear.","TWN":"差點忘記有個聽力很好的女生呢。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_ON","text":{"KOREA":"어디 단원으로 삼기에 적합한지 시험해 볼까요?","JPN":"団員としてふさわしいか、試してみましょうか？","ENG":"Shall we see which unit you are most suitable for?","TWN":"來測試看看你有沒有當團員的資格吧？"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_ON","text":{"KOREA":"실패작이 한 번 상쇄시켰으니, 이번에는 조금 더 정교한 소리를 자아내 드리죠.","JPN":"失敗作に一回相殺されましたので、今回はもっと精巧な音を紡いでさしあげましょう。","ENG":"Well, the failed product offset my first attempt, so let us make a more sophisticated sound.","TWN":"失敗品剛才將我的聲音抵銷掉，那這次就來個更美妙的聲音吧？"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_ON","face":"UNIT_PRIDE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"흐엣……?!","JPN":"ええっ……！？","ENG":"What the...?!","TWN":"咦……？！"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"……무사한가, 소녀여.","JPN":"……無事か、少女よ。","ENG":"...Are you unharmed, girl?","TWN":"……少女，你沒事吧？"},"stage":{"bg":"HARMONY_07","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"모르스……? 그 얼굴…… 알렉스 씨랑……?","JPN":"モールス……？　その顔……アレックスさんと……？","ENG":"Mors...? That face... Alex...?","TWN":"莫爾斯……？你的臉……和雅蕾克絲小姐……？"},"stage":{"bg":"HARMONY_07","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"못 볼 꼴을 보여 송구하구나. 수복력이 한계에 도달한 모양이로다.","JPN":"無様な姿も見せてすまない。修復力が限界に達したようだ。","ENG":"My apologies for showing such an unpleasant spectacle. It appears that the repair capability has reached their limit.","TWN":"抱歉，露出我的醜態，看來修復力似乎已經達到極限。"},"stage":{"bg":"HARMONY_07","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"소녀여. 이 전장에선 소리를 피하고 음율을 받아쳐라. 저들의 술수에 당하면 이성이 무너지고 만다.","JPN":"少女よ。この戦場では音を避けて、音律を受け流せ。あやつらの手法にやられたら理性が崩れてしまう。","ENG":"Girl, in this battlefield, avoid all sound and return all melody. Insanity will take hold of you should you fall into their trickery.","TWN":"少女，在戰場上要避開聲音，要是中招就會喪失理智。"},"stage":{"bg":"HARMONY_07","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"그, 그걸 피할 줄 알면 왜 이딴 나라에 처박혀 있겠어요?!","JPN":"そ、そんなの避けられるくらいなら、こんな国に籠ってません！","ENG":"I-If I knew how to avoid it, do you I think I would still be stuck in this country?","TWN":"要…要是我知道怎麼避開，還會被困在這過國家嗎？！"},"stage":{"bg":"HARMONY_07","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NULL","text":{"KOREA":"후훗. 참으로 보기 딱하십니다, 예하.","JPN":"ふふっ。見るに堪えませんね、猊下。","ENG":"Fuu fuu. What a pathetic sight, Eminence.","TWN":"呵呵，我看著都替主教感到難為情呢。"},"stage":{"bg":"HARMONY_07","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NULL","text":{"KOREA":"죄수의 구속복도 모자라, 그런 너덜너덜한 꼴로 활보하고 다니시다니요.","JPN":"罪人の拘束衣を着るだけでなく、そんなボロボロになって歩きまわされるなんて。","ENG":"With that prisoner’s straitjacket, you are walking around in such a ragged state.","TWN":"罪人的囚服還不夠，看你現在這副狼狽樣。"},"stage":{"bg":"HARMONY_07","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NULL","text":{"KOREA":"청중들은 무대 위로 오르는 악기에게 음색만 아니라 외관도 기대하신답니다.","JPN":"聴衆は舞台に上がる楽器に対し、音色だけでなく見かけも期待するのです。","ENG":"The audience judges not only the sound, but the appearance of the instrument on the stage.","TWN":"聽眾們期待的不只是樂器的音色，還有樂器的外觀。"},"stage":{"bg":"HARMONY_07","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"방자한 소리 집어치워라, 마에스트로.","JPN":"生意気なことを言うのはよせ、マエストロ。","ENG":"Cease such mindless drivel, Maestra.","TWN":"收起你那狂妄的發言，指揮家。"},"stage":{"bg":"HARMONY_07","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"핵을 수복하기 위해 힘을 소모했다는 것은 나 또한 쉬이 알 수 있으니.","JPN":"核を修復するのに力を消耗しているということは我にもすぐわかる。","ENG":"It is apparent that you have spent your power reconstructing your core.","TWN":"我也可以輕易得知，修復核心會消耗你的能力。"},"stage":{"bg":"HARMONY_07","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_ON","text":{"KOREA":"글쎄요. 하오나 이 나라의 국민들은 구태여 제가 공을 들일 만큼 성한 상태가 아니더군요.","JPN":"どうでしょうね。しかし、この国の国民はあえて私が念を入れるほどではありませんでした。","ENG":"Well. The people in this country were not in good enough condition for me to put in any effort.","TWN":"是嗎？不過這個國家國民的狀態，沒有好到我需要特別費功夫的程度。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_ON","face":"UNIT_LAUGH"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_ON","text":{"KOREA":"고맙게도 건국절 행사를 위해 방송 중이었죠.","JPN":"ありがたいことに、建国記念日の行事のために放送をしております。","ENG":"Thankfully though, the event was all broadcasted for National Foundation Day.","TWN":"感恩的是，現在正在轉播國慶典禮。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_ON","text":{"KOREA":"전자 신호로 전달하는 것은 다소 까다로우나…… 꽤나 흥미로운 결과가 나오겠어요.","JPN":"電子信号で伝えるのは少々難しいでしょうが……これは興味深い結果が出ると思います。","ENG":"It is a little tricky transmitting electronic signals... But it is going to lead to quite the exciting outcome.","TWN":"雖然用電磁波傳達有點麻煩……不過結果應該會很有趣。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_ON","face":"UNIT_PRIDE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"저…… 저거 지금 전 국민 상대로 머릿속을 헤집어 놓겠다는 거예요? 그냥 장난식으로?","JPN":"あ……あれって、今全国民を相手に頭の中を掻きまわそうっていうことですか？　ただの遊びで？","ENG":"She-she's going to root through everyone’s minds? Just for to have some fun?","TWN":"意……意思是要控制全國民的腦袋嗎？還用一副開玩笑的口吻説？"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L7_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"……그래. 하지만 기갑 병기도 부족한데 더 버티는 건 무리야.","JPN":"……そうね。でも、機甲兵器も足りないのにこれ以上持つのは無理よ。","ENG":"…Yes. There aren’t many armored weapons left. It’s impossible to hold out any longer.","TWN":"……沒錯，但現在機甲兵器的數量不夠，無法再繼續撐下去。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L8_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"그럼 저걸 그냥 내버려 두려고요? 농담이죠?","JPN":"じゃあ、あれを放っておこうって言うんですか？　冗談ですよね？","ENG":"So we’re just going to leave it alone? Are you joking?","TWN":"所以你打算不管嗎？你在跟我開玩笑嗎？"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L9_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"맞아. 우리만으로는 그럴 수밖에 없겠지.","JPN":"もちろん。私たちだけではね。","ENG":"That’s right. If we’re just on our own, that’s all we can do.","TWN":"沒錯，這是我們唯一的選擇。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L11_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"그래도 우리 뒤에는 뭐든 대비해 두는 척척박사가 계시거든.","JPN":"でも、私たちの後ろには何事にも備えておく物知り博士がいらっしゃるからね。","ENG":"Still, we have a complete Know-it-all behind us, who is prepared for anything.","TWN":"不過我們還有一個凡事都有預備的萬事通可以靠。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"척척…… 그게 누군데요?","JPN":"物知り……それって誰ですか？","ENG":"Know-it-all... Who’s that?","TWN":"萬事通……哪位？"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_ON","text":{"KOREA":"기기들이 꽤나 발전했군요. 조율은 마쳤습니다.","JPN":"機器がかなり発展しましたね。調律は終わりました。","ENG":"The instruments are quite advanced. I am finished tuning.","TWN":"機器進步不少呢，調好音囉。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_ON","face":"UNIT_PRIDE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_ON","text":{"KOREA":"자, 셰나. 카르멘. 시작은 열렬하게 가 볼까요?","JPN":"さあ、シェナ。カルメン。始めはアパッシオナートに行きましょうか？","ENG":"Now, Shena. Carmen. Shall we get started enthusiastically?","TWN":"來吧，世娜、卡門，開場來點震撼的吧？"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_ON","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_QM","text":{"KOREA":"죄송하지만 그건 안 되겠습니다. 침식체.","JPN":"すみませんが、そうはいきません。侵食体。","ENG":"I’m afraid I can’t let that happen. Corrupted Object.","TWN":"抱歉，那是不允許的，侵蝕體。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_ON","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_ON","text":{"KOREA":"이 힘은…….","JPN":"この力は……","ENG":"This power...","TWN":"這股力量是……"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"HORIZON_COLD_NULL_ON","text":{"KOREA":"침식체 하나만 상대하면 된다고 하더니 수준이 다른 개체 아닙니까.","JPN":"相手は侵食体一体と言っておいて、桁違いの個体の相手をさせるとは。","ENG":"I was told that there was only one Corrupted Object to deal with, but it is on an entirely different level.","TWN":"還說只需要對付一個侵蝕體，結果其他個體的水準根本無法相比。"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_COLD_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"HORIZON_COLD_NULL_ON","text":{"KOREA":"역시 휴먼들은 거짓말쟁이들뿐입니다. 냉각판의 표면 온도가 상승하는군요.","JPN":"やはりヒューマンは嘘つきばかりです。冷却板の表面温度が上昇しますね。","ENG":"I knew it. Humans are all liars. The surface temperature of the cooling plate is increasing.","TWN":"人類果然是說謊成性，我的冷卻板表面現在升溫中。"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_COLD_NULL_ON","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_ON","text":{"KOREA":"전의를 불태우는 건 아군이 아닌 적을 향해서 하도록.","JPN":"戦意を燃やす対象は味方ではなく、敵だ。","ENG":"Harness that fighting spirit against the enemy, not our allies.","TWN":"你的鬥志不要對準我們，要對準敵人。"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_ON","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_ON","text":{"KOREA":"오래 기다리게 했군, 알렉스. 대원들은 모두 무사한가?","JPN":"待たせたな、アレックス。隊員はみんな無事か？","ENG":"We’ve kept you waiting a long time, Alex. Is everyone safe?","TWN":"久等了，雅蕾克絲。大家都沒事吧？"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_ON","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"}]`);export{e as default};